<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Maze Game - 24 Bots</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      background: linear-gradient(135deg, #1e1e2e 0%, #2d2d44 100%);
      display: flex;
      justify-content: center;
      align-items: center;
      min-height: 100vh;
      color: #fff;
    }
    .container {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 20px;
      padding: 20px;
    }
    h1 {
      font-size: 32px;
      text-shadow: 0 0 10px rgba(255, 255, 255, 0.5);
    }
    #maze {
      border: 3px solid #fff;
      box-shadow: 0 0 20px rgba(255, 255, 255, 0.3);
      display: block;
      background-color: #000;
      width: 400px;
      height: 400px;
    }
    .hud {
      display: flex;
      gap: 40px;
      font-size: 20px;
      background: rgba(255, 255, 255, 0.1);
      padding: 15px 30px;
      border-radius: 8px;
      backdrop-filter: blur(10px);
    }
    .hud-item {
      display: flex;
      align-items: center;
      gap: 12px;
    }
    .hud-label {
      font-weight: bold;
      color: #4af;
    }
    .hud-value {
      font-weight: bold;
      color: #fff;
      font-size: 24px;
    }
    #reset {
      padding: 12px 30px;
      font-size: 16px;
      font-weight: bold;
      background: linear-gradient(135deg, #4CAF50 0%, #45a049 100%);
      color: white;
      border: none;
      border-radius: 6px;
      cursor: pointer;
      transition: all 0.3s ease;
      box-shadow: 0 4px 15px rgba(76, 175, 80, 0.4);
    }
    #reset:hover {
      transform: translateY(-2px);
      box-shadow: 0 6px 20px rgba(76, 175, 80, 0.6);
    }
    #reset:active {
      transform: translateY(0);
    }
  </style>
</head>
<body>
  <div class="container">
    <h1>🎮 Maze Game</h1>
    <canvas id="maze"></canvas>
    <div class="hud">
      <div class="hud-item">
        <span class="hud-label">Bots Completed:</span>
        <span class="hud-value" id="completed">0</span>/24
      </div>
      <div class="hud-item">
        <span class="hud-label">Time:</span>
        <span class="hud-value" id="timer">0.0s</span>
      </div>
    </div>
    <button id="reset">Reset Game</button>
  </div>

  <script>
    class MazeGenerator {
      constructor(width, height) {
        this.width = width;
        this.height = height;
        this.grid = this.generateMaze();
      }

      generateMaze() {
        const grid = Array(this.height).fill(null).map(() =>
          Array(this.width).fill(1)
        );

        const visit = (x, y) => {
          grid[y][x] = 0;
          const dirs = [[0, -2], [2, 0], [0, 2], [-2, 0]].sort(() => Math.random() - 0.5);

          for (const [dx, dy] of dirs) {
            const nx = x + dx;
            const ny = y + dy;

            if (nx >= 0 && nx < this.width && ny >= 0 && ny < this.height && grid[ny][nx] === 1) {
              grid[y + dy / 2][x + dx / 2] = 0;
              visit(nx, ny);
            }
          }
        };

        visit(0, 0);
        return grid;
      }
    }

    class MazeGame {
      constructor() {
        this.canvas = document.getElementById('maze');
        this.ctx = this.canvas.getContext('2d');
        this.completedEl = document.getElementById('completed');
        this.timerEl = document.getElementById('timer');
        this.resetBtn = document.getElementById('reset');

        this.canvas.width = 400;
        this.canvas.height = 400;

        this.MAZE_SIZE = 31;
        this.CELL_SIZE = this.canvas.width / this.MAZE_SIZE;

        this.init();
        this.resetBtn.addEventListener('click', () => this.reset());
        this.lastFrameTime = performance.now();
        this.animationFrame = requestAnimationFrame(() => this.animate());
      }

      init() {
        this.maze = new MazeGenerator(this.MAZE_SIZE, this.MAZE_SIZE);
        this.spawn = { x: 0, y: 0 };
        this.exit = { x: this.MAZE_SIZE - 1, y: this.MAZE_SIZE - 1 };

        this.maze.grid[0][0] = 0;
        this.maze.grid[this.MAZE_SIZE - 1][this.MAZE_SIZE - 1] = 0;

        this.bots = Array(24).fill(null).map((_, i) => ({
          id: i,
          x: this.spawn.x,
          y: this.spawn.y,
          path: [],
          pathIndex: 0,
          startStep: Math.floor(i * 1.5),
          completed: false
        }));

        this.bots.forEach(bot => {
          bot.path = this.findPath(this.spawn, this.exit);
        });

        this.stepCount = 0;
        this.completedCount = 0;
        this.startTime = performance.now();
      }

      findPath(start, end) {
        const queue = [[start.x, start.y]];
        const visited = new Set([`${start.x},${start.y}`]);
        const parent = new Map();
        parent.set(`${start.x},${start.y}`, null);

        while (queue.length > 0) {
          const [x, y] = queue.shift();

          if (x === end.x && y === end.y) {
            const path = [];
            let curr = `${x},${y}`;
            while (curr !== null) {
              const [cx, cy] = curr.split(',').map(Number);
              path.unshift({ x: cx, y: cy });
              curr = parent.get(curr);
            }
            return path;
          }

          for (const [dx, dy] of [[0, 1], [1, 0], [0, -1], [-1, 0]]) {
            const nx = x + dx;
            const ny = y + dy;
            const key = `${nx},${ny}`;

            if (nx >= 0 && nx < this.MAZE_SIZE && ny >= 0 && ny < this.MAZE_SIZE &&
                this.maze.grid[ny][nx] === 0 && !visited.has(key)) {
              visited.add(key);
              parent.set(key, `${x},${y}`);
              queue.push([nx, ny]);
            }
          }
        }

        return [];
      }

      tick(n) {
        for (let i = 0; i < n; i++) {
          for (const bot of this.bots) {
            if (!bot.completed && this.stepCount >= bot.startStep) {
              if (bot.pathIndex < bot.path.length) {
                const nextPos = bot.path[bot.pathIndex];
                bot.x = nextPos.x;
                bot.y = nextPos.y;
                bot.pathIndex++;

                if (bot.x === this.exit.x && bot.y === this.exit.y) {
                  bot.completed = true;
                  this.completedCount++;
                }
              }
            }
          }
          this.stepCount++;
        }
      }

      reset() {
        cancelAnimationFrame(this.animationFrame);
        this.init();
        this.lastFrameTime = performance.now();
        this.animationFrame = requestAnimationFrame(() => this.animate());
      }

      animate() {
        const now = performance.now();
        const deltaTime = now - this.lastFrameTime;
        this.lastFrameTime = now;

        if (deltaTime > 0) {
          this.tick(1);
        }

        const elapsed = now - this.startTime;
        this.completedEl.textContent = this.completedCount;
        this.timerEl.textContent = (elapsed / 1000).toFixed(1) + 's';

        this.render();
        this.animationFrame = requestAnimationFrame(() => this.animate());
      }

      render() {
        const w = this.canvas.width;
        const h = this.canvas.height;
        const cs = this.CELL_SIZE;

        this.ctx.fillStyle = '#000';
        this.ctx.fillRect(0, 0, w, h);

        this.ctx.fillStyle = '#444';
        for (let y = 0; y < this.MAZE_SIZE; y++) {
          for (let x = 0; x < this.MAZE_SIZE; x++) {
            if (this.maze.grid[y][x] === 1) {
              this.ctx.fillRect(x * cs, y * cs, cs, cs);
            }
          }
        }

        this.ctx.fillStyle = '#0f0';
        this.ctx.fillRect(this.spawn.x * cs, this.spawn.y * cs, cs, cs);

        this.ctx.fillStyle = '#f00';
        this.ctx.fillRect(this.exit.x * cs, this.exit.y * cs, cs, cs);

        for (const bot of this.bots) {
          this.ctx.fillStyle = bot.completed ? '#0ff' : '#ffff00';
          const padding = cs * 0.2;
          this.ctx.fillRect(
            bot.x * cs + padding,
            bot.y * cs + padding,
            cs - padding * 2,
            cs - padding * 2
          );
        }
      }
    }

    const game = new MazeGame();

    window.game = {
      get bots() {
        return game.bots.map(b => ({ x: b.x, y: b.y }));
      },
      get completed() {
        return game.completedCount;
      },
      get elapsedMs() {
        return performance.now() - game.startTime;
      },
      tick(n) {
        game.tick(n);
      },
      reset() {
        game.reset();
      }
    };
  </script>
</body>
</html>
